   293→// TestOutputConsistency tests that all formatters produce consistent output.
   294→func TestOutputConsistency(t *testing.T) {
   295→	result := &CompareResult{
   296→		Source:    "source-org",
   297→		Target:    "target-org",
   298→		Timestamp: "2026-02-05T19:30:00Z",
   299→		Identical: false,
   300→		Blueprints: ResourceDiff{
   301→			Summary: DiffSummary{Added: 2, Modified: 1, Removed: 1},
   302→			Added: []ResourceChange{
   303→				{Identifier: "new-bp-1"},
   304→				{Identifier: "new-bp-2"},
   305→			},
   306→			Modified: []ResourceChange{
   307→				{
   308→					Identifier: "mod-bp",
   309→					FieldDiffs: []FieldDiff{
   310→						{Path: "title", SourceValue: "Old", TargetValue: "New"},
   311→					},
   312→				},
   313→			},
   314→			Removed: []ResourceChange{
   315→				{Identifier: "old-bp"},
   316→			},
   317→		},
   318→	}
   319→
   320→	// Text output
   321→	var textBuf bytes.Buffer
   322→	textFormatter := NewTextFormatter(&textBuf, true, true)
   323→	if err := textFormatter.Format(result); err != nil {
   324→		t.Fatalf("text formatter error: %v", err)
   325→	}
   326→	textOutput := textBuf.String()
   327→
   328→	// JSON output
   329→	var jsonBuf bytes.Buffer
   330→	jsonFormatter := NewJSONFormatter(&jsonBuf)
   331→	if err := jsonFormatter.Format(result); err != nil {
   332→		t.Fatalf("json formatter error: %v", err)
   333→	}
   334→
   335→	// HTML output
   336→	var htmlBuf bytes.Buffer
   337→	htmlFormatter := NewHTMLFormatter(&htmlBuf, false)
   338→	if err := htmlFormatter.Format(result); err != nil {
   339→		t.Fatalf("html formatter error: %v", err)
   340→	}
   341→	htmlOutput := htmlBuf.String()
   342→
   343→	// Verify text contains key information
   344→	if !strings.Contains(textOutput, "source-org") {
   345→		t.Error("text output missing source org name")
   346→	}
   347→	if !strings.Contains(textOutput, "target-org") {
   348→		t.Error("text output missing target org name")
   349→	}
   350→	if !strings.Contains(textOutput, "2 added") {
   351→		t.Error("text output missing '2 added'")
   352→	}
   353→	if !strings.Contains(textOutput, "new-bp-1") {
   354→		t.Error("verbose text output missing added identifier")
   355→	}
   356→
   357→	// Verify JSON is valid and contains key data
   358→	var parsed JSONOutput
   359→	if err := json.Unmarshal(jsonBuf.Bytes(), &parsed); err != nil {
   360→		t.Fatalf("JSON output is invalid: %v", err)
   361→	}
   362→	if parsed.Source != "source-org" {
   363→		t.Errorf("JSON source mismatch: got %s", parsed.Source)
   364→	}
   365→	if parsed.Target != "target-org" {
   366→		t.Errorf("JSON target mismatch: got %s", parsed.Target)
   367→	}
   368→	if parsed.Summary.TotalAdded != 2 {
   369→		t.Errorf("JSON TotalAdded mismatch: expected 2, got %d", parsed.Summary.TotalAdded)
   370→	}
   371→
   372→	// Verify HTML contains key information
   373→	if !strings.Contains(htmlOutput, "<!DOCTYPE html>") {
   374→		t.Error("HTML output missing doctype")
   375→	}
   376→	if !strings.Contains(htmlOutput, "source-org") {
   377→		t.Error("HTML output missing source org name")
   378→	}
   379→	if !strings.Contains(htmlOutput, "target-org") {
   380→		t.Error("HTML output missing target org name")
   381→	}
   382→}
