    83→// LoadWithDualOverrides loads configuration with dual org support.
    84→// Returns config, base org config, and target org config.
    85→// Precedence: CLI flags > env vars > config file > defaults.
    86→func (cm *ConfigManager) LoadWithDualOverrides(
    87→	baseClientID, baseClientSecret, baseAPIURL, baseOrg string,
    88→	targetClientID, targetClientSecret, targetAPIURL, targetOrg string,
    89→) (*Config, *OrganizationConfig, *OrganizationConfig, error) {
    90→	// Load base config (file + env vars)
    91→	cfg, err := cm.Load()
    92→	if err != nil {
    93→		return nil, nil, nil, err
    94→	}
    95→
    96→	// Resolve base org config
    97→	baseOrgConfig, err := cm.resolveOrgConfig(cfg, baseClientID, baseClientSecret, baseAPIURL, baseOrg, "base")
    98→	if err != nil {
    99→		return nil, nil, nil, fmt.Errorf("failed to resolve base org: %w", err)
   100→	}
   101→
   102→	// Resolve target org config
   103→	targetOrgConfig, err := cm.resolveOrgConfig(cfg, targetClientID, targetClientSecret, targetAPIURL, targetOrg, "target")
   104→	if err != nil {
   105→		return nil, nil, nil, fmt.Errorf("failed to resolve target org: %w", err)
   106→	}
   107→
   108→	// If either config is nil and we have an org name, try to get from config file
   109→	if baseOrgConfig == nil && baseOrg != "" {
   110→		baseOrgConfig, err = cfg.GetOrgConfig(baseOrg)
   111→		if err != nil {
   112→			return nil, nil, nil, fmt.Errorf("failed to get base org config: %w", err)
   113→		}
   114→	}
   115→
   116→	if targetOrgConfig == nil && targetOrg != "" {
   117→		targetOrgConfig, err = cfg.GetOrgConfig(targetOrg)
   118→		if err != nil {
   119→			return nil, nil, nil, fmt.Errorf("failed to get target org config: %w", err)
   120→		}
   121→	}
   122→
   123→	return cfg, baseOrgConfig, targetOrgConfig, nil
   124→}
