    13→// Options represents export options.
    14→type Options struct {
    15→	OutputPath       string
    16→	Blueprints       []string
    17→	Format           string
    18→	SkipEntities     bool
    19→	IncludeResources []string
    20→}
    21→
    22→// Validate validates export options.
    23→func (o *Options) Validate() error {
    24→	if o.OutputPath == "" {
    25→		return fmt.Errorf("output_path is required")
    26→	}
    27→
    28→	if o.Format != "" && o.Format != "json" && o.Format != "tar" {
    29→		return fmt.Errorf("format must be 'json' or 'tar'")
    30→	}
    31→
    32→	return nil
    33→}
    34→
    35→// Data represents collected export data.
    36→type Data struct {
    37→	Blueprints    []api.Blueprint
    38→	Entities      []api.Entity
    39→	Scorecards    []api.Scorecard
    40→	Actions       []api.Action
    41→	Teams         []api.Team
    42→	Users         []api.User
    43→	Pages         []api.Page
    44→	Integrations  []api.Integration
    45→	TimeoutErrors []string // Blueprints that timed out during export
    46→}
    47→
    48→// Collector collects data from Port API concurrently.
    49→type Collector struct {
    50→	client *api.Client
    51→}
    52→
    53→// NewCollector creates a new collector.
    54→func NewCollector(client *api.Client) *Collector {
    55→	return &Collector{
    56→		client: client,
    57→	}
    58→}
    59→
    60→// shouldCollect checks if a resource type should be collected.
    61→func shouldCollect(resourceType string, includeResources []string) bool {
    62→	if len(includeResources) == 0 {
    63→		return true
    64→	}
    65→
    66→	for _, r := range includeResources {
    67→		if r == resourceType {
    68→			return true
    69→		}
    70→	}
    71→	return false
    72→}
    73→
    74→// isTimeoutError checks if an error is a timeout error (504 Gateway Timeout).
    75→func isTimeoutError(err error) bool {
    76→	if err == nil {
    77→		return false
    78→	}
    79→	errStr := strings.ToLower(err.Error())
    80→	// Check for various timeout indicators
    81→	return strings.Contains(errStr, "504") ||
    82→		strings.Contains(errStr, "gateway timeout") ||
    83→		strings.Contains(errStr, "timeout_error") ||
    84→		strings.Contains(errStr, "request was too long") ||
    85→		strings.Contains(errStr, "timeout")
    86→}
    87→
    88→// Collect collects all data from Port API concurrently.
    89→func (c *Collector) Collect(ctx context.Context, opts Options) (*Data, error) {
    90→	data := &Data{
    91→		Blueprints:    []api.Blueprint{},
    92→		Entities:      []api.Entity{},
    93→		Scorecards:    []api.Scorecard{},
    94→		Actions:       []api.Action{},
    95→		Teams:         []api.Team{},
    96→		Users:         []api.User{},
    97→		Pages:         []api.Page{},
    98→		Integrations:  []api.Integration{},
    99→		TimeoutErrors: []string{},
   100→	}
   101→
   102→	// Collect blueprints first (needed for other resources)
   103→	var blueprints []api.Blueprint
   104→	if shouldCollect("blueprints", opts.IncludeResources) {
   105→		allBlueprints, err := c.client.GetBlueprints(ctx)
   106→		if err != nil {
   107→			return nil, fmt.Errorf("failed to get blueprints: %w", err)
   108→		}
   109→
   110→		// Filter blueprints if specified
   111→		if len(opts.Blueprints) > 0 {
   112→			blueprintSet := make(map[string]bool)
   113→			for _, bpID := range opts.Blueprints {
   114→				blueprintSet[bpID] = true
   115→			}
   116→
   117→			for _, bp := range allBlueprints {
   118→				if identifier, ok := bp["identifier"].(string); ok && blueprintSet[identifier] {
   119→					blueprints = append(blueprints, bp)
   120→				}
   121→			}
   122→		} else {
   123→			blueprints = allBlueprints
   124→		}
   125→
   126→		data.Blueprints = blueprints
   127→	} else {
   128→		// Still need blueprints for dependent resources
   129→		allBlueprints, err := c.client.GetBlueprints(ctx)
   130→		if err != nil {
   131→			return nil, fmt.Errorf("failed to get blueprints: %w", err)
   132→		}
   133→
   134→		if len(opts.Blueprints) > 0 {
   135→			blueprintSet := make(map[string]bool)
   136→			for _, bpID := range opts.Blueprints {
   137→				blueprintSet[bpID] = true
   138→			}
   139→
   140→			for _, bp := range allBlueprints {
   141→				if identifier, ok := bp["identifier"].(string); ok && blueprintSet[identifier] {
   142→					blueprints = append(blueprints, bp)
   143→				}
   144→			}
   145→		} else {
   146→			blueprints = allBlueprints
   147→		}
   148→	}
   149→
   150→	// Use errgroup for concurrent collection
   151→	g, ctx := errgroup.WithContext(ctx)
   152→	var mu sync.Mutex
   153→	var timeoutErrors []string // Track timeout errors separately
   154→
   155→	// Collect entities, scorecards, and actions concurrently per blueprint
   156→	for _, blueprint := range blueprints {
   157→		bp := blueprint
   158→		bpID, ok := bp["identifier"].(string)
   159→		if !ok {
   160→			continue
   161→		}
   162→
   163→		// Collect entities
   164→		if !opts.SkipEntities && shouldCollect("entities", opts.IncludeResources) {
   165→			g.Go(func() error {
   166→				entities, err := c.client.GetEntities(ctx, bpID, nil)
   167→				if err != nil {
   168→					// Handle expected errors gracefully
   169→					if strings.Contains(err.Error(), "410 Gone") {
   170→						// Blueprint without entities - expected case
   171→						return nil
   172→					}
   173→
   174→					// Handle timeout errors gracefully - skip this blueprint instead of failing entire export
   175→					if isTimeoutError(err) {
   176→						// Collect timeout error but don't fail the export
   177→						mu.Lock()
   178→						timeoutErrors = append(timeoutErrors, fmt.Sprintf("Blueprint %s: timeout getting entities (skipped)", bpID))
   179→						mu.Unlock()
   180→						// Return nil to allow export to continue
   181→						return nil
   182→					}
   183→
   184→					// Other errors are still failures
   185→					return fmt.Errorf("failed to get entities for blueprint %s: %w", bpID, err)
   186→				}
   187→
   188→				mu.Lock()
   189→				data.Entities = append(data.Entities, entities...)
   190→				mu.Unlock()
   191→				return nil
   192→			})
   193→		}
   194→
   195→		// Collect scorecards
   196→		if shouldCollect("scorecards", opts.IncludeResources) {
   197→			g.Go(func() error {
   198→				scorecards, err := c.client.GetScorecards(ctx, bpID)
   199→				if err != nil {
   200→					// Silent skip for expected errors
   201→					if !strings.Contains(err.Error(), "410 Gone") {
   202→						return fmt.Errorf("failed to get scorecards for blueprint %s: %w", bpID, err)
   203→					}
   204→					return nil
   205→				}
   206→
   207→				// Ensure scorecards have blueprintIdentifier field
   208→				for i := range scorecards {
   209→					if _, exists := scorecards[i]["blueprintIdentifier"]; !exists {
   210→						scorecards[i]["blueprintIdentifier"] = bpID
   211→					}
   212→				}
   213→
   214→				mu.Lock()
   215→				data.Scorecards = append(data.Scorecards, scorecards...)
   216→				mu.Unlock()
   217→				return nil
   218→			})
   219→		}
   220→
   221→		// Collect actions
   222→		if shouldCollect("actions", opts.IncludeResources) {
   223→			g.Go(func() error {
   224→				actions, err := c.client.GetActions(ctx, bpID)
   225→				if err != nil {
   226→					// Silent skip for expected errors
   227→					if !strings.Contains(err.Error(), "410 Gone") {
   228→						return fmt.Errorf("failed to get actions for blueprint %s: %w", bpID, err)
   229→					}
   230→					return nil
   231→				}
   232→
   233→				mu.Lock()
   234→				data.Actions = append(data.Actions, actions...)
   235→				mu.Unlock()
   236→				return nil
   237→			})
   238→		}
   239→	}
   240→
   241→	// Collect organization-wide resources
   242→	if shouldCollect("teams", opts.IncludeResources) {
   243→		g.Go(func() error {
   244→			teams, err := c.client.GetTeams(ctx)
   245→			if err != nil {
   246→				return fmt.Errorf("failed to get teams: %w", err)
   247→			}
   248→
   249→			mu.Lock()
   250→			data.Teams = teams
   251→			mu.Unlock()
   252→			return nil
   253→		})
   254→	}
   255→
   256→	// Collect users
   257→	if shouldCollect("users", opts.IncludeResources) {
   258→		g.Go(func() error {
   259→			users, err := c.client.GetUsers(ctx)
   260→			if err != nil {
   261→				return fmt.Errorf("failed to get users: %w", err)
   262→			}
   263→
   264→			mu.Lock()
   265→			data.Users = users
   266→			mu.Unlock()
   267→			return nil
   268→		})
   269→	}
   270→
   271→	// Collect organization-wide automations (via GetAllActions) and merge into actions
   272→	if shouldCollect("actions", opts.IncludeResources) || shouldCollect("automations", opts.IncludeResources) {
   273→		g.Go(func() error {
   274→			allActions, err := c.client.GetAllActions(ctx)
   275→			if err != nil {
   276→				return fmt.Errorf("failed to get all actions/automations: %w", err)
   277→			}
   278→
   279→			mu.Lock()
   280→			data.Actions = append(data.Actions, allActions...)
   281→			mu.Unlock()
   282→			return nil
   283→		})
   284→	}
   285→
   286→	if shouldCollect("pages", opts.IncludeResources) {
   287→		g.Go(func() error {
   288→			pages, err := c.client.GetPages(ctx)
   289→			if err != nil {
   290→				return fmt.Errorf("failed to get pages: %w", err)
   291→			}
   292→
   293→			mu.Lock()
   294→			data.Pages = pages
   295→			mu.Unlock()
   296→			return nil
   297→		})
   298→	}
   299→
   300→	if shouldCollect("integrations", opts.IncludeResources) {
   301→		g.Go(func() error {
   302→			integrations, err := c.client.GetIntegrations(ctx)
   303→			if err != nil {
   304→				return fmt.Errorf("failed to get integrations: %w", err)
   305→			}
   306→
   307→			mu.Lock()
   308→			data.Integrations = integrations
   309→			mu.Unlock()
   310→			return nil
   311→		})
   312→	}
   313→
   314→	// Wait for all goroutines to complete
   315→	if err := g.Wait(); err != nil {
   316→		return nil, err
   317→	}
   318→
   319→	// Attach timeout errors to data
   320→	data.TimeoutErrors = timeoutErrors
   321→
   322→	return data, nil
   323→}
