   101→// normalizeResource normalizes a resource by removing system fields and ensuring consistent structure.
   102→func normalizeResource(resource map[string]interface{}, systemFields []string) map[string]interface{} {
   103→	normalized := make(map[string]interface{})
   104→	removeSet := make(map[string]bool)
   105→	for _, f := range systemFields {
   106→		removeSet[f] = true
   107→	}
   108→
   109→	for k, v := range resource {
   110→		if !removeSet[k] {
   111→			normalized[k] = normalizeValue(v)
   112→		}
   113→	}
   114→
   115→	return normalized
   116→}
   117→
   118→// normalizeValue recursively normalizes a value for comparison.
   119→func normalizeValue(v interface{}) interface{} {
   120→	switch val := v.(type) {
   121→	case map[string]interface{}:
   122→		normalized := make(map[string]interface{})
   123→		for k, v := range val {
   124→			normalized[k] = normalizeValue(v)
   125→		}
   126→		return normalized
   127→	case []interface{}:
   128→		normalized := make([]interface{}, len(val))
   129→		for i, item := range val {
   130→			normalized[i] = normalizeValue(item)
   131→		}
   132→		// Sort slice only if ALL elements are strings
   133→		if len(normalized) > 0 {
   134→			allStrings := true
   135→			for _, item := range normalized {
   136→				if _, ok := item.(string); !ok {
   137→					allStrings = false
   138→					break
   139→				}
   140→			}
   141→			if allStrings {
   142→				sort.Slice(normalized, func(i, j int) bool {
   143→					return normalized[i].(string) < normalized[j].(string)
   144→				})
   145→			}
   146→		}
   147→		return normalized
   148→	default:
   149→		return v
   150→	}
   151→}
   152→
   153→// resourcesEqual checks if two resources are equal after normalization.
   154→func resourcesEqual(a, b map[string]interface{}, systemFields []string) bool {
   155→	normA := normalizeResource(a, systemFields)
   156→	normB := normalizeResource(b, systemFields)
   157→
   158→	// Use JSON marshaling for deep comparison
   159→	jsonA, errA := json.Marshal(normA)
   160→	jsonB, errB := json.Marshal(normB)
   161→
   162→	if errA != nil || errB != nil {
   163→		// Fallback to reflect.DeepEqual if JSON fails
   164→		return reflect.DeepEqual(normA, normB)
   165→	}
   166→
   167→	return string(jsonA) == string(jsonB)
   168→}
   169→
   170→// portManagedBlueprints are blueprints that are fully managed by Port and cannot be modified.
   171→// These are skipped during import to avoid "protected_blueprint_violation" errors.
   172→var portManagedBlueprints = map[string]bool{
   173→	"_rule": true, // Managed through scorecards, not directly editable
   174→}
   175→
   176→// compareBlueprints compares import blueprints with current blueprints.
   177→func (d *DiffComparer) compareBlueprints(importBPs, currentBPs []api.Blueprint, includeResources []string) (create, update, skip []api.Blueprint) {
   178→	if !shouldImport("blueprints", includeResources) {
   179→		return nil, nil, nil
   180→	}
   181→
   182→	currentMap := make(map[string]api.Blueprint)
   183→	for _, bp := range currentBPs {
   184→		if identifier, ok := bp["identifier"].(string); ok {
   185→			currentMap[identifier] = bp
   186→		}
   187→	}
   188→
   189→	for _, bp := range importBPs {
   190→		identifier, ok := bp["identifier"].(string)
   191→		if !ok || identifier == "" {
   192→			continue
   193→		}
   194→
   195→		// Skip Port-managed blueprints that cannot be modified directly
   196→		if portManagedBlueprints[identifier] {
   197→			skip = append(skip, bp)
   198→			continue
   199→		}
   200→
