   100→// toMaps converts a slice of typed maps to []map[string]interface{}.
   101→func toMaps[T ~map[string]interface{}](items []T) []map[string]interface{} {
   102→	result := make([]map[string]interface{}, len(items))
   103→	for i, item := range items {
   104→		result[i] = map[string]interface{}(item)
   105→	}
   106→	return result
   107→}
   108→
   109→// diffResources compares two slices of resources by identifier.
   110→func diffResources(source, target []map[string]interface{}, idField string) ResourceDiff {
   111→	result := ResourceDiff{}
   112→
   113→	// Build lookup maps
   114→	sourceMap := make(map[string]map[string]interface{})
   115→	targetMap := make(map[string]map[string]interface{})
   116→
   117→	for _, item := range source {
   118→		if id, ok := item[idField].(string); ok {
   119→			sourceMap[id] = item
   120→		}
   121→	}
   122→	for _, item := range target {
   123→		if id, ok := item[idField].(string); ok {
   124→			targetMap[id] = item
   125→		}
   126→	}
   127→
   128→	// Find added (in target but not in source)
   129→	for id, targetItem := range targetMap {
   130→		if _, exists := sourceMap[id]; !exists {
   131→			result.Added = append(result.Added, ResourceChange{
   132→				Identifier: id,
   133→				TargetData: targetItem,
   134→			})
   135→		}
   136→	}
   137→
   138→	// Find removed (in source but not in target)
   139→	for id, sourceItem := range sourceMap {
   140→		if _, exists := targetMap[id]; !exists {
   141→			result.Removed = append(result.Removed, ResourceChange{
   142→				Identifier: id,
   143→				SourceData: sourceItem,
   144→			})
   145→		}
   146→	}
   147→
   148→	// Find modified (in both, but different)
   149→	for id, sourceItem := range sourceMap {
   150→		if targetItem, exists := targetMap[id]; exists {
   151→			fieldDiffs := diffFields(sourceItem, targetItem, "")
   152→			if len(fieldDiffs) > 0 {
   153→				result.Modified = append(result.Modified, ResourceChange{
   154→					Identifier: id,
   155→					SourceData: sourceItem,
   156→					TargetData: targetItem,
   157→					FieldDiffs: fieldDiffs,
   158→				})
   159→			}
   160→		}
   161→	}
   162→
   163→	// Sort for consistent output
   164→	sort.Slice(result.Added, func(i, j int) bool { return result.Added[i].Identifier < result.Added[j].Identifier })
   165→	sort.Slice(result.Removed, func(i, j int) bool { return result.Removed[i].Identifier < result.Removed[j].Identifier })
   166→	sort.Slice(result.Modified, func(i, j int) bool { return result.Modified[i].Identifier < result.Modified[j].Identifier })
   167→
   168→	result.Summary = DiffSummary{
   169→		Added:    len(result.Added),
   170→		Modified: len(result.Modified),
   171→		Removed:  len(result.Removed),
   172→	}
   173→
   174→	return result
   175→}
   176→
   177→// diffFields recursively compares two maps and returns field differences.
   178→func diffFields(source, target map[string]interface{}, prefix string) []FieldDiff {
   179→	var diffs []FieldDiff
   180→
   181→	// Collect all keys from both maps
   182→	allKeys := make(map[string]bool)
   183→	for k := range source {
   184→		allKeys[k] = true
   185→	}
   186→	for k := range target {
   187→		allKeys[k] = true
   188→	}
   189→
   190→	for key := range allKeys {
   191→		// Skip excluded fields
   192→		if ExcludedFields[key] {
   193→			continue
   194→		}
   195→
   196→		path := key
   197→		if prefix != "" {
   198→			path = prefix + "." + key
   199→		}
   200→
   201→		sourceVal, sourceExists := source[key]
   202→		targetVal, targetExists := target[key]
   203→
   204→		if !sourceExists {
   205→			diffs = append(diffs, FieldDiff{
   206→				Path:        path,
   207→				SourceValue: nil,
   208→				TargetValue: targetVal,
   209→			})
   210→		} else if !targetExists {
   211→			diffs = append(diffs, FieldDiff{
   212→				Path:        path,
   213→				SourceValue: sourceVal,
   214→				TargetValue: nil,
   215→			})
   216→		} else if !reflect.DeepEqual(sourceVal, targetVal) {
   217→			// Check if both are maps for recursive comparison
   218→			sourceMap, sourceIsMap := sourceVal.(map[string]interface{})
   219→			targetMap, targetIsMap := targetVal.(map[string]interface{})
   220→
   221→			if sourceIsMap && targetIsMap {
   222→				diffs = append(diffs, diffFields(sourceMap, targetMap, path)...)
   223→			} else {
   224→				diffs = append(diffs, FieldDiff{
   225→					Path:        path,
   226→					SourceValue: sourceVal,
   227→					TargetValue: targetVal,
   228→				})
   229→			}
   230→		}
   231→	}
   232→
   233→	// Sort for consistent output
   234→	sort.Slice(diffs, func(i, j int) bool {
   235→		return diffs[i].Path < diffs[j].Path
   236→	})
   237→
   238→	return diffs
   239→}
   240→
   241→// FormatPath formats a diff path for display.
   242→func FormatPath(path string) string {
   243→	if len(path) > 0 && path[0] == '.' {
   244→		return path[1:]
   245→	}
   246→	return path
   247→}
