   142→func TestClient_request_Retry(t *testing.T) {
   143→	attempts := 0
   144→	// Create a mock server that returns 429 on first attempt
   145→	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
   146→		if r.URL.Path == "/auth/access_token" {
   147→			response := TokenResponse{
