   154→			return
   155→		}
   156→
   157→		attempts++
   158→		if attempts == 1 {
   159→			w.WriteHeader(http.StatusTooManyRequests)
   160→			return
   161→		}
   162→
   163→		w.Header().Set("Content-Type", "application/json")
   164→		w.WriteHeader(http.StatusOK)
   165→		json.NewEncoder(w).Encode(map[string]string{"status": "ok"})
   166→	}))
   167→	defer server.Close()
