   175→	}
   176→	defer resp.Body.Close()
   177→
   178→	if attempts != 2 {
   179→		t.Errorf("Expected 2 attempts (retry on 429), got %d", attempts)
   180→	}
   181→
   182→	if resp.StatusCode != http.StatusOK {
