    20→// Client handles authenticated requests to Port's API.
    21→type Client struct {
    22→	httpClient *http.Client
    23→	tokenMgr   *TokenManager
    24→	apiURL     string
    25→	timeout    time.Duration
    26→}
    27→
    28→// TokenResponse represents the Port API token response.
    29→type TokenResponse struct {
    30→	AccessToken string `json:"accessToken"`
    31→	ExpiresIn   int    `json:"expiresIn"`
    32→	TokenType   string `json:"tokenType"`
    33→}
    34→
    35→// NewClient creates a new Port API client.
    36→func NewClient(clientID, clientSecret, apiURL string, timeout time.Duration) *Client {
    37→	if apiURL == "" {
    38→		apiURL = "https://api.getport.io/v1"
    39→	}
    40→	if timeout == 0 {
    41→		timeout = 300 * time.Second
    42→	}
    43→
    44→	// Remove trailing slash
    45→	if len(apiURL) > 0 && apiURL[len(apiURL)-1] == '/' {
    46→		apiURL = apiURL[:len(apiURL)-1]
    47→	}
    48→
    49→	return &Client{
    50→		httpClient: &http.Client{
    51→			Timeout: timeout,
    52→		},
    53→		tokenMgr: NewTokenManager(clientID, clientSecret, apiURL),
    54→		apiURL:   apiURL,
    55→		timeout:  timeout,
    56→	}
    57→}
    58→
    59→// getToken gets or refreshes the authentication token.
    60→func (c *Client) getToken(ctx context.Context) (string, error) {
    61→	token, err := c.tokenMgr.GetToken()
    62→	if err == nil && token != "" {
    63→		return token, nil
    64→	}
    65→
    66→	// Refresh token
    67→	return c.refreshToken(ctx)
    68→}
    69→
    70→// refreshToken requests a new token from the API.
    71→func (c *Client) refreshToken(ctx context.Context) (string, error) {
    72→	authURL := fmt.Sprintf("%s/auth/access_token", c.apiURL)
    73→	payload := map[string]string{
    74→		"clientId":     c.tokenMgr.ClientID,
    75→		"clientSecret": c.tokenMgr.ClientSecret,
    76→	}
    77→
    78→	reqBody, err := json.Marshal(payload)
