    24→	if o.OutputPath == "" {
    25→		return fmt.Errorf("output_path is required")
    26→	}
    27→
    28→	if o.Format != "" && o.Format != "json" && o.Format != "tar" {
    29→		return fmt.Errorf("format must be 'json' or 'tar'")
