    60→// shouldCollect checks if a resource type should be collected.
    61→func shouldCollect(resourceType string, includeResources []string) bool {
    62→	if len(includeResources) == 0 {
    63→		return true
    64→	}
    65→
    66→	for _, r := range includeResources {
    67→		if r == resourceType {
    68→			return true
    69→		}
    70→	}
    71→	return false
    72→}
