    74→// isTimeoutError checks if an error is a timeout error (504 Gateway Timeout).
    75→func isTimeoutError(err error) bool {
    76→	if err == nil {
    77→		return false
    78→	}
    79→	errStr := strings.ToLower(err.Error())
    80→	// Check for various timeout indicators
    81→	return strings.Contains(errStr, "504") ||
    82→		strings.Contains(errStr, "gateway timeout") ||
    83→		strings.Contains(errStr, "timeout_error") ||
    84→		strings.Contains(errStr, "request was too long") ||
    85→		strings.Contains(errStr, "timeout")
    86→}
