    88→// Collect collects all data from Port API concurrently.
    89→func (c *Collector) Collect(ctx context.Context, opts Options) (*Data, error) {
    90→	data := &Data{
    91→		Blueprints:    []api.Blueprint{},
    92→		Entities:      []api.Entity{},
    93→		Scorecards:    []api.Scorecard{},
    94→		Actions:       []api.Action{},
    95→		Teams:         []api.Team{},
    96→		Users:         []api.User{},
    97→		Pages:         []api.Page{},
    98→		Integrations:  []api.Integration{},
    99→		TimeoutErrors: []string{},
   100→	}
   101→
   102→	// Collect blueprints first (needed for other resources)
   103→	var blueprints []api.Blueprint
   104→	if shouldCollect("blueprints", opts.IncludeResources) {
   105→		allBlueprints, err := c.client.GetBlueprints(ctx)
   106→		if err != nil {
   107→			return nil, fmt.Errorf("failed to get blueprints: %w", err)
   108→		}
   109→
   110→		// Filter blueprints if specified
   111→		if len(opts.Blueprints) > 0 {
   112→			blueprintSet := make(map[string]bool)
   113→			for _, bpID := range opts.Blueprints {
   114→				blueprintSet[bpID] = true
   115→			}
   116→
   117→			for _, bp := range allBlueprints {
   118→				if identifier, ok := bp["identifier"].(string); ok && blueprintSet[identifier] {
   119→					blueprints = append(blueprints, bp)
   120→				}
   121→			}
   122→		} else {
   123→			blueprints = allBlueprints
   124→		}
   125→
   126→		data.Blueprints = blueprints
   127→	} else {
   128→		// Still need blueprints for dependent resources
   129→		allBlueprints, err := c.client.GetBlueprints(ctx)
   130→		if err != nil {
   131→			return nil, fmt.Errorf("failed to get blueprints: %w", err)
   132→		}
   133→
   134→		if len(opts.Blueprints) > 0 {
   135→			blueprintSet := make(map[string]bool)
   136→			for _, bpID := range opts.Blueprints {
   137→				blueprintSet[bpID] = true
   138→			}
   139→
   140→			for _, bp := range allBlueprints {
   141→				if identifier, ok := bp["identifier"].(string); ok && blueprintSet[identifier] {
   142→					blueprints = append(blueprints, bp)
   143→				}
   144→			}
   145→		} else {
   146→			blueprints = allBlueprints
   147→		}
   148→	}
