   151→	g, ctx := errgroup.WithContext(ctx)
   152→	var mu sync.Mutex
   153→	var timeoutErrors []string // Track timeout errors separately
   154→
   155→	// Collect entities, scorecards, and actions concurrently per blueprint
   156→	for _, blueprint := range blueprints {
   157→		bp := blueprint
   158→		bpID, ok := bp["identifier"].(string)
   159→		if !ok {
   160→			continue
   161→		}
   162→
   163→		// Collect entities
   164→		if !opts.SkipEntities && shouldCollect("entities", opts.IncludeResources) {
   165→			g.Go(func() error {
   166→				entities, err := c.client.GetEntities(ctx, bpID, nil)
   167→				if err != nil {
   168→					// Handle expected errors gracefully
   169→					if strings.Contains(err.Error(), "410 Gone") {
   170→						// Blueprint without entities - expected case
   171→						return nil
   172→					}
   173→
