   177→						mu.Lock()
   178→						timeoutErrors = append(timeoutErrors, fmt.Sprintf("Blueprint %s: timeout getting entities (skipped)", bpID))
   179→						mu.Unlock()
   180→						// Return nil to allow export to continue
   181→						return nil
   182→					}
   183→
   184→					// Other errors are still failures
   185→					return fmt.Errorf("failed to get entities for blueprint %s: %w", bpID, err)
   186→				}
   187→
   188→				mu.Lock()
   189→				data.Entities = append(data.Entities, entities...)
   190→				mu.Unlock()
   191→				return nil
   192→			})
   193→		}
   194→
   195→		// Collect scorecards
   196→		if shouldCollect("scorecards", opts.IncludeResources) {
   197→			g.Go(func() error {
   198→				scorecards, err := c.client.GetScorecards(ctx, bpID)
   199→				if err != nil {
   200→					// Silent skip for expected errors
   201→					if !strings.Contains(err.Error(), "410 Gone") {
   202→						return fmt.Errorf("failed to get scorecards for blueprint %s: %w", bpID, err)
   203→					}
   204→					return nil
   205→				}
   206→
   207→				// Ensure scorecards have blueprintIdentifier field
   208→				for i := range scorecards {
   209→					if _, exists := scorecards[i]["blueprintIdentifier"]; !exists {
   210→						scorecards[i]["blueprintIdentifier"] = bpID
   211→					}
   212→				}
   213→
   214→				mu.Lock()
   215→				data.Scorecards = append(data.Scorecards, scorecards...)
   216→				mu.Unlock()
   217→				return nil
   218→			})
   219→		}
   220→
   221→		// Collect actions
   222→		if shouldCollect("actions", opts.IncludeResources) {
   223→			g.Go(func() error {
   224→				actions, err := c.client.GetActions(ctx, bpID)
   225→				if err != nil {
   226→					// Silent skip for expected errors
   227→					if !strings.Contains(err.Error(), "410 Gone") {
   228→						return fmt.Errorf("failed to get actions for blueprint %s: %w", bpID, err)
   229→					}
   230→					return nil
   231→				}
   232→
   233→				mu.Lock()
   234→				data.Actions = append(data.Actions, actions...)
   235→				mu.Unlock()
   236→				return nil
   237→			})
   238→		}
   239→	}
   240→
   241→	// Collect organization-wide resources
   242→	if shouldCollect("teams", opts.IncludeResources) {
   243→		g.Go(func() error {
   244→			teams, err := c.client.GetTeams(ctx)
   245→			if err != nil {
   246→				return fmt.Errorf("failed to get teams: %w", err)
   247→			}
   248→
   249→			mu.Lock()
   250→			data.Teams = teams
   251→			mu.Unlock()
   252→			return nil
   253→		})
   254→	}
   255→
   256→	// Collect users
   257→	if shouldCollect("users", opts.IncludeResources) {
   258→		g.Go(func() error {
   259→			users, err := c.client.GetUsers(ctx)
   260→			if err != nil {
   261→				return fmt.Errorf("failed to get users: %w", err)
   262→			}
   263→
   264→			mu.Lock()
   265→			data.Users = users
   266→			mu.Unlock()
   267→			return nil
   268→		})
   269→	}
   270→
   271→	// Collect organization-wide automations (via GetAllActions) and merge into actions
   272→	if shouldCollect("actions", opts.IncludeResources) || shouldCollect("automations", opts.IncludeResources) {
   273→		g.Go(func() error {
   274→			allActions, err := c.client.GetAllActions(ctx)
   275→			if err != nil {
   276→				return fmt.Errorf("failed to get all actions/automations: %w", err)
   277→			}
   278→
   279→			mu.Lock()
   280→			data.Actions = append(data.Actions, allActions...)
   281→			mu.Unlock()
   282→			return nil
   283→		})
   284→	}
   285→
   286→	if shouldCollect("pages", opts.IncludeResources) {
   287→		g.Go(func() error {
   288→			pages, err := c.client.GetPages(ctx)
   289→			if err != nil {
   290→				return fmt.Errorf("failed to get pages: %w", err)
   291→			}
   292→
   293→			mu.Lock()
   294→			data.Pages = pages
   295→			mu.Unlock()
   296→			return nil
   297→		})
   298→	}
   299→
   300→	if shouldCollect("integrations", opts.IncludeResources) {
   301→		g.Go(func() error {
   302→			integrations, err := c.client.GetIntegrations(ctx)
   303→			if err != nil {
   304→				return fmt.Errorf("failed to get integrations: %w", err)
   305→			}
   306→
   307→			mu.Lock()
   308→			data.Integrations = integrations
   309→			mu.Unlock()
   310→			return nil
   311→		})
   312→	}
   313→
   314→	// Wait for all goroutines to complete
   315→	if err := g.Wait(); err != nil {
   316→		return nil, err
   317→	}
   318→
   319→	// Attach timeout errors to data
   320→	data.TimeoutErrors = timeoutErrors
   321→
   322→	return data, nil
   323→}
