    13→func TestOptions_Validate(t *testing.T) {
    14→	tests := []struct {
    15→		name    string
    16→		options Options
    17→		wantErr bool
    18→	}{
    19→		{
    20→			name: "valid options",
    21→			options: Options{
    22→				OutputPath: "/tmp/test.json",
    23→				Format:     "json",
    24→			},
    25→			wantErr: false,
    26→		},
    27→		{
    28→			name: "missing output path",
    29→			options: Options{
    30→				Format: "json",
    31→			},
    32→			wantErr: true,
    33→		},
    34→		{
    35→			name: "invalid format",
    36→			options: Options{
    37→				OutputPath: "/tmp/test.json",
    38→				Format:     "xml",
    39→			},
    40→			wantErr: true,
    41→		},
    42→	}
    43→
    44→	for _, tt := range tests {
    45→		t.Run(tt.name, func(t *testing.T) {
    46→			err := tt.options.Validate()
    47→			if (err != nil) != tt.wantErr {
    48→				t.Errorf("Validate() error = %v, wantErr %v", err, tt.wantErr)
    49→			}
    50→		})
    51→	}
    52→}
