    58→func NewCollector(client *api.Client) *Collector {
    59→	return &Collector{
    60→		client: client,
    61→	}
    62→}
    63→
    64→// shouldCollect checks if a resource type should be collected.
    65→func shouldCollect(resourceType string, includeResources []string) bool {
    66→	if len(includeResources) == 0 {
    67→		return true
    68→	}
    69→
    70→	for _, r := range includeResources {
    71→		if r == resourceType {
    72→			return true
    73→		}
    74→	}
    75→	return false
    76→}
    77→
    78→// isTimeoutError checks if an error is a timeout error (504 Gateway Timeout).
    79→func isTimeoutError(err error) bool {
    80→	if err == nil {
    81→		return false
    82→	}
    83→	errStr := strings.ToLower(err.Error())
    84→	// Check for various timeout indicators
    85→	return strings.Contains(errStr, "504") ||
    86→		strings.Contains(errStr, "gateway timeout") ||
    87→		strings.Contains(errStr, "timeout_error") ||
    88→		strings.Contains(errStr, "request was too long") ||
    89→		strings.Contains(errStr, "timeout")
    90→}
    91→
    92→// Collect collects all data from Port API concurrently.
    93→func (c *Collector) Collect(ctx context.Context, opts Options) (*Data, error) {
    94→	data := &Data{
    95→		Blueprints:           []api.Blueprint{},
    96→		Entities:             []api.Entity{},
    97→		Scorecards:           []api.Scorecard{},
    98→		Actions:              []api.Action{},
    99→		Teams:                []api.Team{},
   100→		Users:                []api.User{},
   101→		Pages:                []api.Page{},
   102→		Integrations:         []api.Integration{},
   103→		TimeoutErrors:        []string{},
   104→		BlueprintPermissions: make(map[string]api.Permissions),
   105→		ActionPermissions:    make(map[string]api.Permissions),
   106→	}
   107→
   108→	// Collect blueprints first (needed for other resources)
   109→	var blueprints []api.Blueprint
   110→	if shouldCollect("blueprints", opts.IncludeResources) {
   111→		allBlueprints, err := c.client.GetBlueprints(ctx)
   112→		if err != nil {
   113→			return nil, fmt.Errorf("failed to get blueprints: %w", err)
   114→		}
   115→
   116→		// Filter blueprints if specified
   117→		if len(opts.Blueprints) > 0 {
   118→			blueprintSet := make(map[string]bool)
   119→			for _, bpID := range opts.Blueprints {
   120→				blueprintSet[bpID] = true
   121→			}
   122→
   123→			for _, bp := range allBlueprints {
   124→				if identifier, ok := bp["identifier"].(string); ok && blueprintSet[identifier] {
   125→					blueprints = append(blueprints, bp)
   126→				}
   127→			}
   128→		} else {
   129→			blueprints = allBlueprints
   130→		}
   131→
   132→		data.Blueprints = blueprints
   133→	} else {
   134→		// Still need blueprints for dependent resources
   135→		allBlueprints, err := c.client.GetBlueprints(ctx)
   136→		if err != nil {
   137→			return nil, fmt.Errorf("failed to get blueprints: %w", err)
   138→		}
   139→
   140→		if len(opts.Blueprints) > 0 {
   141→			blueprintSet := make(map[string]bool)
   142→			for _, bpID := range opts.Blueprints {
   143→				blueprintSet[bpID] = true
   144→			}
   145→
   146→			for _, bp := range allBlueprints {
   147→				if identifier, ok := bp["identifier"].(string); ok && blueprintSet[identifier] {
   148→					blueprints = append(blueprints, bp)
   149→				}
   150→			}
   151→		} else {
   152→			blueprints = allBlueprints
   153→		}
   154→	}
   155→
   156→	// Use errgroup for concurrent collection
   157→	g, ctx := errgroup.WithContext(ctx)
   158→	var mu sync.Mutex
   159→	var timeoutErrors []string // Track timeout errors separately
   160→
   161→	// Collect entities, scorecards, and actions concurrently per blueprint
   162→	for _, blueprint := range blueprints {
   163→		bp := blueprint
   164→		bpID, ok := bp["identifier"].(string)
   165→		if !ok {
   166→			continue
   167→		}
   168→
   169→		// Collect entities
   170→		if !opts.SkipEntities && shouldCollect("entities", opts.IncludeResources) {
   171→			g.Go(func() error {
   172→				entities, err := c.client.GetEntities(ctx, bpID, nil)
   173→				if err != nil {
   174→					// Handle expected errors gracefully
   175→					if strings.Contains(err.Error(), "410 Gone") {
   176→						// Blueprint without entities - expected case
   177→						return nil
   178→					}
   179→
   180→					// Handle timeout errors gracefully - skip this blueprint instead of failing entire export
   181→					if isTimeoutError(err) {
   182→						// Collect timeout error but don't fail the export
   183→						mu.Lock()
   184→						timeoutErrors = append(timeoutErrors, fmt.Sprintf("Blueprint %s: timeout getting entities (skipped)", bpID))
   185→						mu.Unlock()
   186→						// Return nil to allow export to continue
   187→						return nil
   188→					}
   189→
   190→					// Other errors are still failures
   191→					return fmt.Errorf("failed to get entities for blueprint %s: %w", bpID, err)
   192→				}
   193→
   194→				mu.Lock()
   195→				data.Entities = append(data.Entities, entities...)
   196→				mu.Unlock()
   197→				return nil
   198→			})
   199→		}
   200→
   201→		// Collect scorecards
   202→		if shouldCollect("scorecards", opts.IncludeResources) {
   203→			g.Go(func() error {
   204→				scorecards, err := c.client.GetScorecards(ctx, bpID)
   205→				if err != nil {
   206→					// Silent skip for expected errors
   207→					if !strings.Contains(err.Error(), "410 Gone") {
   208→						return fmt.Errorf("failed to get scorecards for blueprint %s: %w", bpID, err)
   209→					}
   210→					return nil
   211→				}
   212→
   213→				// Ensure scorecards have blueprintIdentifier field
   214→				for i := range scorecards {
   215→					if _, exists := scorecards[i]["blueprintIdentifier"]; !exists {
   216→						scorecards[i]["blueprintIdentifier"] = bpID
   217→					}
   218→				}
   219→
   220→				mu.Lock()
   221→				data.Scorecards = append(data.Scorecards, scorecards...)
   222→				mu.Unlock()
   223→				return nil
   224→			})
   225→		}
   226→
   227→		// Collect actions (and their permissions)
   228→		if shouldCollect("actions", opts.IncludeResources) {
   229→			g.Go(func() error {
   230→				actions, err := c.client.GetActions(ctx, bpID)
   231→				if err != nil {
   232→					// Silent skip for expected errors
   233→					if !strings.Contains(err.Error(), "410 Gone") {
   234→						return fmt.Errorf("failed to get actions for blueprint %s: %w", bpID, err)
   235→					}
   236→					return nil
   237→				}
   238→
   239→				mu.Lock()
   240→				data.Actions = append(data.Actions, actions...)
   241→				mu.Unlock()
   242→
   243→				// Fetch permissions for each action
   244→				for _, action := range actions {
   245→					actionID, ok := action["identifier"].(string)
   246→					if !ok {
   247→						continue
   248→					}
   249→					aID := actionID // capture for goroutine closure
   250→					g.Go(func() error {
   251→						perms, err := c.client.GetActionPermissions(ctx, aID)
   252→						if err != nil {
   253→							// Non-fatal: skip silently
   254→							return nil
   255→						}
   256→						mu.Lock()
   257→						data.ActionPermissions[aID] = perms
   258→						mu.Unlock()
   259→						return nil
   260→					})
   261→				}
   262→				return nil
   263→			})
   264→		}
   265→
   266→		// Collect blueprint permissions
   267→		if shouldCollect("blueprint-permissions", opts.IncludeResources) || len(opts.IncludeResources) == 0 {
   268→			bpIDCopy := bpID // capture for goroutine closure
   269→			g.Go(func() error {
   270→				perms, err := c.client.GetBlueprintPermissions(ctx, bpIDCopy)
   271→				if err != nil {
   272→					// Non-fatal: permissions fetch failure should not abort the export
   273→					return nil
   274→				}
   275→				mu.Lock()
   276→				data.BlueprintPermissions[bpIDCopy] = perms
   277→				mu.Unlock()
   278→				return nil
   279→			})
   280→		}
   281→	}
   282→
   283→	// Collect organization-wide resources
   284→	if shouldCollect("teams", opts.IncludeResources) {
   285→		g.Go(func() error {
   286→			teams, err := c.client.GetTeams(ctx)
   287→			if err != nil {
   288→				return fmt.Errorf("failed to get teams: %w", err)
   289→			}
   290→
   291→			mu.Lock()
   292→			data.Teams = teams
   293→			mu.Unlock()
   294→			return nil
   295→		})
   296→	}
   297→
   298→	// Collect users
   299→	if shouldCollect("users", opts.IncludeResources) {
   300→		g.Go(func() error {
   301→			users, err := c.client.GetUsers(ctx)
   302→			if err != nil {
   303→				return fmt.Errorf("failed to get users: %w", err)
   304→			}
   305→
   306→			mu.Lock()
   307→			data.Users = users
   308→			mu.Unlock()
   309→			return nil
   310→		})
   311→	}
   312→
   313→	// Collect organization-wide automations (via GetAllActions) and merge into actions
   314→	if shouldCollect("actions", opts.IncludeResources) || shouldCollect("automations", opts.IncludeResources) {
   315→		g.Go(func() error {
   316→			allActions, err := c.client.GetAllActions(ctx)
   317→			if err != nil {
   318→				return fmt.Errorf("failed to get all actions/automations: %w", err)
   319→			}
   320→
   321→			mu.Lock()
   322→			data.Actions = append(data.Actions, allActions...)
   323→			mu.Unlock()
   324→
   325→			// Fetch permissions for each org-wide action
   326→			for _, action := range allActions {
   327→				actionID, ok := action["identifier"].(string)
   328→				if !ok {
   329→					continue
   330→				}
   331→				aID := actionID // capture for goroutine closure
   332→				g.Go(func() error {
   333→					perms, err := c.client.GetActionPermissions(ctx, aID)
   334→					if err != nil {
   335→						// Non-fatal: skip silently
   336→						return nil
   337→					}
   338→					mu.Lock()
   339→					data.ActionPermissions[aID] = perms
   340→					mu.Unlock()
   341→					return nil
   342→				})
   343→			}
   344→			return nil
   345→		})
   346→	}
   347→
   348→	if shouldCollect("pages", opts.IncludeResources) {
   349→		g.Go(func() error {
   350→			pages, err := c.client.GetPages(ctx)
   351→			if err != nil {
   352→				return fmt.Errorf("failed to get pages: %w", err)
   353→			}
   354→
   355→			mu.Lock()
   356→			data.Pages = pages
   357→			mu.Unlock()
   358→			return nil
   359→		})
   360→	}
   361→
   362→	if shouldCollect("integrations", opts.IncludeResources) {
   363→		g.Go(func() error {
   364→			integrations, err := c.client.GetIntegrations(ctx)
   365→			if err != nil {
   366→				return fmt.Errorf("failed to get integrations: %w", err)
   367→			}
   368→
   369→			mu.Lock()
   370→			data.Integrations = integrations
   371→			mu.Unlock()
   372→			return nil
   373→		})
   374→	}
   375→
   376→	// Wait for all goroutines to complete
   377→	if err := g.Wait(); err != nil {
   378→		return nil, err
   379→	}
   380→
   381→	// Attach timeout errors to data
   382→	data.TimeoutErrors = timeoutErrors
   383→
   384→	return data, nil
   385→}
