   113→// normalizeResource normalizes a resource by removing system fields and ensuring consistent structure.
   114→func normalizeResource(resource map[string]interface{}, systemFields []string) map[string]interface{} {
   115→	normalized := make(map[string]interface{})
   116→	removeSet := make(map[string]bool)
   117→	for _, f := range systemFields {
   118→		removeSet[f] = true
   119→	}
   120→
   121→	for k, v := range resource {
   122→		if !removeSet[k] {
   123→			normalized[k] = normalizeValue(v)
   124→		}
   125→	}
   126→
   127→	return normalized
   128→}
   129→
   130→// normalizeValue recursively normalizes a value for comparison.
   131→func normalizeValue(v interface{}) interface{} {
   132→	switch val := v.(type) {
   133→	case map[string]interface{}:
   134→		normalized := make(map[string]interface{})
   135→		for k, v := range val {
   136→			normalized[k] = normalizeValue(v)
   137→		}
   138→		return normalized
   139→	case []interface{}:
   140→		normalized := make([]interface{}, len(val))
   141→		for i, item := range val {
   142→			normalized[i] = normalizeValue(item)
   143→		}
   144→		// Sort slice only if ALL elements are strings
   145→		if len(normalized) > 0 {
   146→			allStrings := true
   147→			for _, item := range normalized {
   148→				if _, ok := item.(string); !ok {
   149→					allStrings = false
   150→					break
   151→				}
   152→			}
   153→			if allStrings {
   154→				sort.Slice(normalized, func(i, j int) bool {
   155→					return normalized[i].(string) < normalized[j].(string)
   156→				})
   157→			}
   158→		}
   159→		return normalized
   160→	default:
   161→		return v
   162→	}
   163→}
   164→
   165→// resourcesEqual checks if two resources are equal after normalization.
   166→func resourcesEqual(a, b map[string]interface{}, systemFields []string) bool {
   167→	normA := normalizeResource(a, systemFields)
   168→	normB := normalizeResource(b, systemFields)
   169→
   170→	// Use JSON marshaling for deep comparison
   171→	jsonA, errA := json.Marshal(normA)
   172→	jsonB, errB := json.Marshal(normB)
   173→
   174→	if errA != nil || errB != nil {
   175→		// Fallback to reflect.DeepEqual if JSON fails
   176→		return reflect.DeepEqual(normA, normB)
   177→	}
   178→
   179→	return string(jsonA) == string(jsonB)
   180→}
