    38→// Diff compares source and target org data, optionally filtered to specific resource types.
    39→// An empty include slice means all resource types are compared.
    40→func (d *Differ) Diff(source, target *export.Data, include []string) *CompareResult {
    41→	result := &CompareResult{
    42→		Identical: true,
    43→	}
    44→
    45→	// Compare each resource type, skipping those not in the include list
    46→	if shouldInclude("blueprints", include) {
    47→		result.Blueprints = d.diffBlueprints(source.Blueprints, target.Blueprints)
    48→	}
    49→	if shouldInclude("actions", include) {
    50→		result.Actions = d.diffActions(source.Actions, target.Actions)
    51→	}
    52→	if shouldInclude("scorecards", include) {
    53→		result.Scorecards = d.diffScorecards(source.Scorecards, target.Scorecards)
    54→	}
    55→	if shouldInclude("pages", include) {
    56→		result.Pages = d.diffPages(source.Pages, target.Pages)
    57→	}
    58→	if shouldInclude("integrations", include) {
    59→		result.Integrations = d.diffIntegrations(source.Integrations, target.Integrations)
    60→	}
    61→	if shouldInclude("teams", include) {
    62→		result.Teams = d.diffTeams(source.Teams, target.Teams)
    63→	}
    64→	if shouldInclude("users", include) {
    65→		result.Users = d.diffUsers(source.Users, target.Users)
    66→	}
    67→	// Note: automations are fetched via the collector's "automations" keyword but merged
    68→	// into Actions in export.Data; result.Automations remains a zero-value placeholder.
    69→
    70→	if shouldInclude("blueprint-permissions", include) {
    71→		result.BlueprintPermissions = d.diffPermissions(source.BlueprintPermissions, target.BlueprintPermissions)
    72→	}
    73→	if shouldInclude("action-permissions", include) {
    74→		result.ActionPermissions = d.diffPermissions(source.ActionPermissions, target.ActionPermissions)
    75→	}
    76→
    77→	// Check if any differences exist
    78→	result.Identical = d.isIdentical(result)
