   144→			for k, v := range perms {
   145→				entry[k] = v
   146→			}
   147→			entry["identifier"] = id
   148→			result = append(result, entry)
   149→		}
   150→		return result
   151→	}
   152→	return diffResources(toSlice(source), toSlice(target), "identifier")
