   155→// toMaps converts a slice of typed maps to []map[string]interface{}.
   156→func toMaps[T ~map[string]interface{}](items []T) []map[string]interface{} {
   157→	result := make([]map[string]interface{}, len(items))
   158→	for i, item := range items {
   159→		result[i] = map[string]interface{}(item)
   160→	}
   161→	return result
   162→}
   163→
   164→// diffResources compares two slices of resources by identifier.
   165→func diffResources(source, target []map[string]interface{}, idField string) ResourceDiff {
   166→	result := ResourceDiff{}
   167→
   168→	// Build lookup maps
   169→	sourceMap := make(map[string]map[string]interface{})
   170→	targetMap := make(map[string]map[string]interface{})
   171→
   172→	for _, item := range source {
   173→		if id, ok := item[idField].(string); ok {
   174→			sourceMap[id] = item
   175→		}
   176→	}
   177→	for _, item := range target {
   178→		if id, ok := item[idField].(string); ok {
   179→			targetMap[id] = item
   180→		}
   181→	}
   182→
   183→	// Find added (in target but not in source)
   184→	for id, targetItem := range targetMap {
   185→		if _, exists := sourceMap[id]; !exists {
   186→			result.Added = append(result.Added, ResourceChange{
   187→				Identifier: id,
   188→				TargetData: targetItem,
   189→			})
   190→		}
   191→	}
   192→
   193→	// Find removed (in source but not in target)
   194→	for id, sourceItem := range sourceMap {
   195→		if _, exists := targetMap[id]; !exists {
   196→			result.Removed = append(result.Removed, ResourceChange{
   197→				Identifier: id,
   198→				SourceData: sourceItem,
   199→			})
   200→		}
   201→	}
   202→
   203→	// Find modified (in both, but different)
   204→	for id, sourceItem := range sourceMap {
   205→		if targetItem, exists := targetMap[id]; exists {
   206→			fieldDiffs := diffFields(sourceItem, targetItem, "")
   207→			if len(fieldDiffs) > 0 {
   208→				result.Modified = append(result.Modified, ResourceChange{
   209→					Identifier: id,
   210→					SourceData: sourceItem,
   211→					TargetData: targetItem,
   212→					FieldDiffs: fieldDiffs,
   213→				})
   214→			}
   215→		}
   216→	}
   217→
   218→	// Sort for consistent output
   219→	sort.Slice(result.Added, func(i, j int) bool { return result.Added[i].Identifier < result.Added[j].Identifier })
   220→	sort.Slice(result.Removed, func(i, j int) bool { return result.Removed[i].Identifier < result.Removed[j].Identifier })
   221→	sort.Slice(result.Modified, func(i, j int) bool { return result.Modified[i].Identifier < result.Modified[j].Identifier })
   222→
   223→	result.Summary = DiffSummary{
   224→		Added:    len(result.Added),
   225→		Modified: len(result.Modified),
   226→		Removed:  len(result.Removed),
   227→	}
   228→
   229→	return result
   230→}
   231→
   232→// diffFields recursively compares two maps and returns field differences.
   233→func diffFields(source, target map[string]interface{}, prefix string) []FieldDiff {
   234→	var diffs []FieldDiff
   235→
   236→	// Collect all keys from both maps
   237→	allKeys := make(map[string]bool)
   238→	for k := range source {
   239→		allKeys[k] = true
   240→	}
   241→	for k := range target {
   242→		allKeys[k] = true
   243→	}
   244→
   245→	for key := range allKeys {
   246→		// Skip excluded fields
   247→		if ExcludedFields[key] {
   248→			continue
   249→		}
   250→
   251→		path := key
   252→		if prefix != "" {
   253→			path = prefix + "." + key
   254→		}
   255→
   256→		sourceVal, sourceExists := source[key]
   257→		targetVal, targetExists := target[key]
   258→
   259→		if !sourceExists {
   260→			diffs = append(diffs, FieldDiff{
   261→				Path:        path,
   262→				SourceValue: nil,
   263→				TargetValue: targetVal,
   264→			})
   265→		} else if !targetExists {
   266→			diffs = append(diffs, FieldDiff{
   267→				Path:        path,
   268→				SourceValue: sourceVal,
   269→				TargetValue: nil,
   270→			})
   271→		} else if !reflect.DeepEqual(sourceVal, targetVal) {
   272→			// Check if both are maps for recursive comparison
   273→			sourceMap, sourceIsMap := sourceVal.(map[string]interface{})
   274→			targetMap, targetIsMap := targetVal.(map[string]interface{})
   275→
   276→			if sourceIsMap && targetIsMap {
   277→				diffs = append(diffs, diffFields(sourceMap, targetMap, path)...)
   278→			} else {
   279→				diffs = append(diffs, FieldDiff{
   280→					Path:        path,
   281→					SourceValue: sourceVal,
   282→					TargetValue: targetVal,
   283→				})
   284→			}
   285→		}
   286→	}
   287→
   288→	// Sort for consistent output
   289→	sort.Slice(diffs, func(i, j int) bool {
   290→		return diffs[i].Path < diffs[j].Path
   291→	})
   292→
   293→	return diffs
   294→}
   295→
   296→// FormatPath formats a diff path for display.
   297→func FormatPath(path string) string {
   298→	if len(path) > 0 && path[0] == '.' {
   299→		return path[1:]
   300→	}
   301→	return path
   302→}
