    10→// TextFormatter formats comparison results as text.
    11→type TextFormatter struct {
    12→	w       io.Writer
    13→	verbose bool
    14→	full    bool
    15→}
    16→
    17→// NewTextFormatter creates a new text formatter.
    18→func NewTextFormatter(w io.Writer, verbose, full bool) *TextFormatter {
    19→	return &TextFormatter{
    20→		w:       w,
    21→		verbose: verbose,
    22→		full:    full,
    23→	}
    24→}
    25→
    26→// Format outputs the comparison result as text.
    27→func (f *TextFormatter) Format(result *CompareResult) error {
    28→	// Header
    29→	fmt.Fprintf(f.w, "Comparing %s -> %s\n\n", result.Source, result.Target)
    30→
    31→	// Summary for each resource type
    32→	f.formatResourceType("Blueprints", result.Blueprints)
    33→	f.formatResourceType("Actions", result.Actions)
    34→	f.formatResourceType("Scorecards", result.Scorecards)
    35→	f.formatResourceType("Pages", result.Pages)
    36→	f.formatResourceType("Integrations", result.Integrations)
    37→	f.formatResourceType("Teams", result.Teams)
    38→	f.formatResourceType("Users", result.Users)
    39→	f.formatResourceType("Automations", result.Automations)
    40→	f.formatResourceType("Blueprint Permissions", result.BlueprintPermissions)
    41→	f.formatResourceType("Action Permissions", result.ActionPermissions)
    42→
    43→	// Total
    44→	total := f.calculateTotal(result)
    45→	fmt.Fprintf(f.w, "\nTotal: %d added, %d modified, %d removed\n",
    46→		total.Added, total.Modified, total.Removed)
    47→
    48→	if result.Identical {
    49→		fmt.Fprintf(f.w, "\nOrganizations are identical.\n")
    50→	}
    51→
    52→	return nil
    53→}
    54→
    55→func (f *TextFormatter) formatResourceType(name string, diff ResourceDiff) {
    56→	s := diff.Summary
    57→
    58→	if s.Added == 0 && s.Modified == 0 && s.Removed == 0 {
    59→		fmt.Fprintf(f.w, "%-14s identical\n", name+":")
    60→		return
    61→	}
    62→
    63→	fmt.Fprintf(f.w, "%-14s %d added, %d modified, %d removed\n",
    64→		name+":", s.Added, s.Modified, s.Removed)
    65→
    66→	// Verbose: show identifiers
    67→	if f.verbose || f.full {
    68→		if len(diff.Added) > 0 {
    69→			ids := f.getIdentifiers(diff.Added)
    70→			fmt.Fprintf(f.w, "  Added:    %s\n", strings.Join(ids, ", "))
    71→		}
    72→		if len(diff.Modified) > 0 {
    73→			ids := f.getIdentifiers(diff.Modified)
    74→			fmt.Fprintf(f.w, "  Modified: %s\n", strings.Join(ids, ", "))
    75→		}
    76→		if len(diff.Removed) > 0 {
    77→			ids := f.getIdentifiers(diff.Removed)
    78→			fmt.Fprintf(f.w, "  Removed:  %s\n", strings.Join(ids, ", "))
    79→		}
    80→	}
    81→
    82→	// Full: show field-level diffs
    83→	if f.full {
    84→		for _, change := range diff.Added {
    85→			fmt.Fprintf(f.w, "\n  [+] %s (added)\n", change.Identifier)
    86→			f.formatData(change.TargetData, "      ")
    87→		}
    88→		for _, change := range diff.Modified {
    89→			fmt.Fprintf(f.w, "\n  [~] %s (modified)\n", change.Identifier)
    90→			for _, fd := range change.FieldDiffs {
    91→				fmt.Fprintf(f.w, "      %s:\n", fd.Path)
    92→				fmt.Fprintf(f.w, "        - %v\n", fd.SourceValue)
    93→				fmt.Fprintf(f.w, "        + %v\n", fd.TargetValue)
    94→			}
    95→		}
    96→		for _, change := range diff.Removed {
    97→			fmt.Fprintf(f.w, "\n  [-] %s (removed)\n", change.Identifier)
    98→		}
    99→	}
   100→}
   101→
   102→func (f *TextFormatter) getIdentifiers(changes []ResourceChange) []string {
   103→	ids := make([]string, len(changes))
   104→	for i, c := range changes {
   105→		ids[i] = c.Identifier
   106→	}
   107→	return ids
   108→}
   109→
   110→func (f *TextFormatter) formatData(data map[string]interface{}, indent string) {
   111→	for k, v := range data {
   112→		if ExcludedFields[k] {
   113→			continue
   114→		}
   115→		fmt.Fprintf(f.w, "%s%s: %v\n", indent, k, v)
   116→	}
   117→}
   118→
   119→func (f *TextFormatter) calculateTotal(result *CompareResult) DiffSummary {
   120→	resources := []ResourceDiff{
   121→		result.Blueprints, result.Actions, result.Scorecards,
   122→		result.Pages, result.Integrations, result.Teams,
   123→		result.Users, result.Automations,
   124→		result.BlueprintPermissions, result.ActionPermissions,
   125→	}
   126→
   127→	var total DiffSummary
   128→	for _, r := range resources {
   129→		total.Added += r.Summary.Added
   130→		total.Modified += r.Summary.Modified
   131→		total.Removed += r.Summary.Removed
   132→	}
   133→	return total
   134→}
